from math import gcd

def solution(limit: int = 1500000) -> int:
    """
    Counts perimeters L <= limit with exactly one right triangle solution.
    Uses Euclid's formula for generating Pythagorean triples.
    """
    counts = [0] * (limit + 1)

    # Euclid's formula: a = m^2-n^2, b = 2mn, c = m^2+n^2
    # Perimeter P = 2m(m+n)
    m_limit = int((limit // 2)**0.5)

    for m in range(2, m_limit + 1):
        for n in range(1, m):
            # Conditions for primitive triples
            if (m - n) % 2 == 1 and gcd(m, n) == 1:
                p = 2 * m * (m + n)
                # Update all multiples of the primitive perimeter
                for multiple_p in range(p, limit + 1, p):
                    counts[multiple_p] += 1

    return sum(1 for c in counts if c == 1)


if __name__ == "__main__":
    print(f"Result: {solution(1500000)}")

